    const stack = [];
    const pairs = {")": "(", "}": "{", "]": "["};

    for (const ch of s) {
        if (ch in pairs) {
            if (!stack.length || stack[stack.length-1] !== pairs[ch]) {
                return false;
            }
            stack.pop();
        } else {
            stack.push(ch);
        }
    }
    return stack.length === 0;
}

