function bfsLevels(graph, start) {
    const visited = new Set([start]);
    const queue = [start];
    let level = 0;

    while (queue.length > 0) {
        const size = queue.length;
        for (let i = 0; i < size; i++) {
            const node = queue.shift();
            // process node at 'level'

            for (const nb of graph[node]) {
                if (!visited.has(nb)) {
                    visited.add(nb);
                    queue.push(nb);
                }
            }
        }
        level++;
    }
}

